			origCost := asgn.Cost
			ok := asgn.AddShip(id, ori, des)
			if ok {
				asgn.GenRoute()
				newCost := asgn.Cost
				if newCost >= 0 {
					delta := newCost - origCost
					if delta < bestRes.costDelta {
						bestRes.assignIdx = ai
						bestRes.costDelta = delta
						bestRes.ok = true
					}
				}
				// Keep rolled-back if we later choose another assign; otherwise keep
				asgn.RemoveShip(id)
				asgn.GenRoute()
			}
		}
		// Commit the best insertion found
