			targetAsgn := &dispatch.Assigns[bestRes.assignIdx]
			targetAsgn.AddShip(id, ori, des)
			targetAsgn.GenRoute()
			// Extend assignsLen if we used a fresh assign
			if bestRes.assignIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen = bestRes.assignIdx + 1
			}
		} else {
			// Fallback safe seed: create a new assign even if it may increase total vehicles
			fallbackIdx := dispatch.AssignsLen
			if fallbackIdx < MAXASSIGNS {
				asgn := &dispatch.Assigns[fallbackIdx]
				ok := asgn.AddShip(id, ori, des)
				if ok {
