func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for orderIdx := 0; orderIdx < len(oris); orderIdx++ {
		bestAssignIdx := -1
		bestCostDelta := 0.0
		foundFeasible := false

		orderID := total_ship + orderIdx
		ori := oris[orderIdx]
		des := dess[orderIdx]

		// Try existing non‑empty assigns first
		for assignIdx := 0; assignIdx < dispatch.AssignsLen; assignIdx++ {
			assign := &dispatch.Assigns[assignIdx]

			origCost := assign.Cost

			ok := assign.AddShip(orderID, ori, des)
			if !ok {
				continue
			}
			assign.GenRoute()

			if assign.Cost < 0 {
				assign.RemoveShip(orderID)
				assign.GenRoute()
				continue
			}

			costDelta := assign.Cost - origCost

			if !foundFeasible || costDelta < bestCostDelta {
				foundFeasible = true
				bestCostDelta = costDelta
				bestAssignIdx = assignIdx
			}

			assign.RemoveShip(orderID)
			assign.GenRoute()
		}

		// Also consider a brand‑new assign if we haven't reached MAXASSIGNS
		if dispatch.AssignsLen < MAXASSIGNS {
			newAssignIdx := dispatch.AssignsLen
			newAssign := &dispatch.Assigns[newAssignIdx]

			origNewCost := newAssign.Cost

			ok := newAssign.AddShip(orderID, ori, des)
			if ok {
				newAssign.GenRoute()

				if newAssign.Cost >= 0 {
					costDelta := newAssign.Cost - origNewCost

					if !foundFeasible || costDelta < bestCostDelta {
						foundFeasible = true
						bestCostDelta = costDelta
						bestAssignIdx = newAssignIdx
					}
				}

				newAssign.RemoveShip(orderID)
				newAssign.GenRoute()
			}
		}

		// Fallback: if still no feasible slot among existing assigns, force into a new/empty assign
		if !foundFeasible {
			inserted := false
			for i := dispatch.AssignsLen; i < MAXASSIGNS; i++ {
				if dispatch.Assigns[i].AddShip(orderID, ori, des) {
					dispatch.Assigns[i].GenRoute()
					if dispatch.Assigns[i].Cost >= 0 {
