	for idx := 0; idx <= dispatch.AssignsLen; idx++ {
		if idx == MAXASSIGNS {
			continue
		}
		affectedIdx := idx
		if affectedIdx >= dispatch.AssignsLen {
			affectedIdx = dispatch.AssignsLen
		}
		if savedStates[affectedIdx].stationsLen == 0 && affectedIdx < dispatch.AssignsLen {
			savedStates[affectedIdx].stationsLen = dispatch.Assigns[affectedIdx].StationsLen
			savedStates[affectedIdx].cost = dispatch.Assigns[affectedIdx].Cost
		}
		success := dispatch.Assigns[affectedIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
		if success {
			dispatch.Assigns[affectedIdx].GenRoute()
			costAfter := dispatch.Assigns[affectedIdx].Cost
			delta := costAfter - savedStates[affectedIdx].cost
			if delta < bestCostDelta && costAfter >= 0 {
				bestCostDelta = delta
