filtered_best_population_item.algorithm:
For each unassigned order, evaluate insertion into all existing non-empty routes first using cost-delta tracking with full rollback, then try empty/new assigns, always committing the best feasible insertion while preserving all orders.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for orderIdx := 0; orderIdx < len(oris); orderIdx++ {
		bestAssignIdx := -1
		bestCostDelta := 0.0
		foundFeasible := false

		orderID := total_ship + orderIdx
		ori := oris[orderIdx]
		des := dess[orderIdx]

		// Try existing non‑empty assigns first
		for assignIdx := 0; assignIdx < dispatch.AssignsLen; assignIdx++ {
			assign := &dispatch.Assigns[assignIdx]

			origCost := assign.Cost

			ok := assign.AddShip(orderID, ori, des)
			if !ok {
				continue
			}
			assign.GenRoute()

			if assign.Cost < 0 {
				assign.RemoveShip(orderID)
				assign.GenRoute()
				continue
			}

			costDelta := assign.Cost - origCost

			if !foundFeasible || costDelta < bestCostDelta {
				foundFeasible = true
				bestCostDelta = costDelta
				bestAssignIdx = assignIdx
			}

			assign.RemoveShip(orderID)
			assign.GenRoute()
