Weighted regret-based insertion with capacity-aware scoring and time-window feasibility priority}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for shipIdx := range oris {
		id := total_ship + shipIdx
		ori := oris[shipIdx]
		des := dess[shipIdx]

		type candidate struct {
			assignIdx   int
			score       float64
			inserted    bool
		}
		var candidates []candidate

		for assignIdx := 0; assignIdx < dispatch.AssignsLen; assignIdx++ {
			assign := &dispatch.Assigns[assignIdx]

			oldCost := assign.Cost
			feasible := assign.AddShip(id, ori, des)
			if feasible {
				assign.GenRoute()
				newCost := assign.Cost
				costIncrease := newCost - oldCost

				timeWindowPenalty := 0.0
				currentLoad := assign.StationCurrent.Load
				loadAfter := currentLoad + ori.Load
				capacityExcess := loadAfter - 100
				if capacityExcess > 0 {
					timeWindowPenalty += float64(capacityExcess) * 50.0
				}

				waitTime := 0.0
				if ori.TimeStart > 0 || des.TimeStart > 0 {
					arrivalOri := cal_dis(assign.StationCurrent, ori)
					if arrivalOri < float64(ori.TimeStart) {
						waitTime = float64(ori.TimeStart) - arrivalOri
					}
					arrivalDes := arrivalOri + cal_dis(ori, des)
					if arrivalDes < float64(des.TimeStart) {
						waitTime += float64(des.TimeStart) - arrivalDes
					}
				}

				regretScore := costIncrease + timeWindowPenalty*0.3 + waitTime*0.1

				assign.RemoveShip(id)
				assign.GenRoute()

				candidates = append(candidates, candidate{assignIdx: assignIdx, score: regretScore, inserted: true})
			} else {
				assign.RemoveShip(id)
				assign.GenRoute()
			}
		}

		var bestCandidate candidate
		foundFeasible := false
		minScore := 1e30
		for _, c := range candidates {
			if c.inserted && c.score < minScore {
				minScore = c.score
				bestCandidate = c
				foundFeasible = true
			}
		}

		if foundFeasible && bestCandidate.assignIdx >= 0 && bestCandidate.assignIdx < dispatch.AssignsLen {
			target := &dispatch.Assigns[bestCandidate.assignIdx]
			target.AddShip(id, ori, des)
			target.GenRoute()
		} else {
			if dispatch.AssignsLen < MAXASSIGNS {
				newAssign := &dispatch.Assigns[dispatch.AssignsLen]
				if newAssign.AddShip(id, ori, des) {
					newAssign.GenRoute()
					dispatch.AssignsLen++
				} else {
					newAssign.RemoveShip(id)
					newAssign.GenRoute()

					for i := 0; i < dispatch.AssignsLen; i++ {
						temp := &dispatch.Assigns[i]
						if temp.AddShip(id, ori, des) {
							temp.GenRoute()
							break
						} else {
							temp.RemoveShip(id)
							temp.GenRoute()
						}
					}
				}
			} else {
				for i := 0; i < dispatch.AssignsLen; i++ {
					temp := &dispatch.Assigns[i]
					if temp.AddShip(id, ori, des) {
						temp.GenRoute()
						break
					} else {
						temp.RemoveShip(id)
						temp.GenRoute()
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

