		orderId := total_ship + jj
		ori, des := oris[jj], dess[jj]
		for idx := 0; idx <= dispatch.AssignsLen; idx++ {
			if idx == MAXASSIGNS {
				continue
			}
			currAssign := &dispatch.Assigns[idx]
			oldState := currAssign.Cost
			ok := currAssign.AddShip(orderId, ori, des)
			if !ok || currAssign.Cost < 0 {
				if ok {
					currAssign.RemoveShip(orderId)
					currAssign.GenRoute()
				}
				continue
			}
			newCost := currAssign.Cost
			delta := newCost - oldState
			currAssign.RemoveShip(orderId)
			currAssign.GenRoute()
			if ok && delta >= 0 && delta < bestCand.costDelta {
				bestCand.assignIdx = idx
				bestCand.costDelta = delta
				feasibleFound = true
			}
		}
		targetIdx := -1
		if feasibleFound {
			if bestCand.assignIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen++
			}
			targetIdx = bestCand.assignIdx
		} else {
			if dispatch.AssignsLen < MAXASSIGNS {
				targetIdx = dispatch.AssignsLen
				dispatch.AssignsLen++
			} else {
				for i := 0; i < MAXASSIGNS; i++ {
					currAssign := &dispatch.Assigns[i]
