					ok := currAssign.AddShip(orderId, ori, des)
					if !ok || currAssign.Cost < 0 {
						if ok {
							currAssign.RemoveShip(orderId)
							currAssign.GenRoute()
						}
						continue
					}
					newCost := currAssign.Cost
					delta := newCost - oldState
					currAssign.RemoveShip(orderId)
					currAssign.GenRoute()
					if ok && delta >= 0 && delta < bestCand.costDelta {
						bestCand.assignIdx = i
						bestCand.costDelta = delta
						feasibleFound = true
					}
