				if feasibleFound {
					targetIdx = bestCand.assignIdx
				} else {
					targetIdx = dispatch.AssignsLen - 1
				}
			}
		}
		inserted := false
		if targetIdx >= 0 && targetIdx < MAXASSIGNS {
			inserted = dispatch.Assigns[targetIdx].AddShip(orderId, ori, des)
			if inserted {
				dispatch.Assigns[targetIdx].GenRoute()
			}
		}
		if !inserted && dispatch.AssignsLen < MAXASSIGNS {
