func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type trialRecord struct {
		assignIdx int
		costDelta float64
		succeeded bool
	}
	for shipIDOffset := range oris {
		best := trialRecord{-1, 1e100, false}
		ori := oris[shipIDOffset]
		des := dess[shipIDOffset]
		shipID := total_ship + shipIDOffset

		checkAssign := func(assignIdx int, useNewEmpty bool) {
			var curAssign *Assign
			if useNewEmpty {
				if dispatch.AssignsLen >= MAXASSIGNS {
					return
				}
				curAssign = &dispatch.Assigns[dispatch.AssignsLen]
				*curAssign = Assign{}
			} else {
				curAssign = &dispatch.Assigns[assignIdx]
			}
			oldCost := curAssign.Cost
			added := curAssign.AddShip(shipID, ori, des)
			if added {
				curAssign.GenRoute()
				newCost := curAssign.Cost
				if newCost >= 0 {
					delta := newCost - oldCost
					if delta < best.costDelta {
						best.assignIdx = assignIdx
						best.costDelta = delta
						best.succeeded = true
					}
				}
				curAssign.RemoveShip(shipID)
				curAssign.GenRoute()
			}
		}

		for idx := 0; idx < dispatch.AssignsLen; idx++ {
			checkAssign(idx, false)
		}
		checkAssign(-1, true)

		if best.succeeded {
			targetAssign := &dispatch.Assigns[best.assignIdx]
			ok := targetAssign.AddShip(shipID, ori, des)
			if ok {
				targetAssign.GenRoute()
			}
		} else {
