				continue
			}
			newAssign := &dispatch.Assigns[dispatch.AssignsLen]
			ok := newAssign.AddShip(shipID, ori, des)
			if ok {
				newAssign.GenRoute()
				dispatch.AssignsLen++
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

